mapper.select:
SELECT  FROM pdp_domain_package_version
WHERE package_id =
  #{packageId,typeHandler=com.pdp.mysql.typehandler.UuidBinaryTypeHandler}
  AND semantic_version = #{semanticVersion}

SELECT  FROM pdp_domain_package_version
WHERE package_id =
  #{packageId,typeHandler=com.pdp.mysql.typehandler.UuidBinaryTypeHandler}

  AND (
    created_at >
      #{afterCreatedAt,typeHandler=com.pdp.mysql.typehandler.InstantUtcTypeHandler}
    OR (
      created_at =
        #{afterCreatedAt,typeHandler=com.pdp.mysql.typehandler.InstantUtcTypeHandler}
      AND id >
        #{afterId,typeHandler=com.pdp.mysql.typehandler.UuidBinaryTypeHandler}
    )
  )

ORDER BY created_at, id
LIMIT #{limit}
